using namespace std;

class DSU {
    vector<int> parent, rank;
    int count;
public:
    DSU(int n) : parent(n), rank(n), count(n) {
        for (int i = 0; i < n; ++i) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    void union_(int x, int y) {
        int xroot = find(x);
        int yroot = find(y);
        if (xroot == yroot) return;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) rank[xroot]++;
        }
        count--;
    }
    int get_count() { return count; }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    vector<vector<long long>> sorted_edges = edges;
    sort(sorted_edges.begin(), sorted_edges.end(), [](const auto& a, const auto& b) {
        return a[2] < b[2];
    });

    long long low = 0;
    long long high = 0;
    for (auto& e : edges) {
        high = max(high, e[2]);
    }

    long long answer = high;

    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : sorted_edges) {
            if (e[2] <= mid) {
                dsu.union_(e[0], e[1]);
            }
        }
        if (dsu.get_count() <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

