package main

import (
	"sort"
)

type DSU struct {
	parent []int64
	rank   []int64
	count  int64
}

func newDSU(n int64) *DSU {
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := 0; i < int(n); i++ {
		parent[i] = int64(i)
		rank[i] = 1
	}
	return &DSU{
		parent: parent,
		rank:   rank,
		count:  n,
	}
}

func (d *DSU) find(x int64) int64 {
	if d.parent[x] != x {
		d.parent[x] = d.find(d.parent[x])
	}
	return d.parent[x]
}

func (d *DSU) union(x, y int64) {
	xroot := d.find(x)
	yroot := d.find(y)
	if xroot == yroot {
		return
	}
	if d.rank[xroot] < d.rank[yroot] {
		d.parent[xroot] = yroot
	} else {
		d.parent[yroot] = xroot
		if d.rank[xroot] == d.rank[yroot] {
			d.rank[xroot]++
		}
	}
	d.count--
}

func (d *DSU) getCount() int64 {
	return d.count
}

func solve(n int64, edges [][]int64, k int64) int64 {
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	var high int64
	for _, e := range edges {
		if e[2] > high {
			high = e[2]
		}
	}

	var answer int64 = high

	for low := int64(0); low <= high; {
		mid := (low + high) / 2
		dsu := newDSU(n)
		for _, e := range edges {
			if e[2] <= mid {
				dsu.union(e[0], e[1])
			}
		}
		count := dsu.getCount()
		if count <= k {
			answer = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}

	return answer
}
