package main

import (
	"sort"
)

type DSU struct {
	parent []int
	rank   []int
	count  int
}

func NewDSU(n int) *DSU {
	parent := make([]int, n)
	rank := make([]int, n)
	for i := 0; i < n; i++ {
		parent[i] = i
		rank[i] = 0
	}
	return &DSU{parent, rank, n}
}

func (dsu *DSU) find(x int) int {
	if dsu.parent[x] != x {
		dsu.parent[x] = dsu.find(dsu.parent[x])
	}
	return dsu.parent[x]
}

func (dsu *DSU) union(x, y int) {
	xroot := dsu.find(x)
	yroot := dsu.find(y)
	if xroot == yroot {
		return
	}
	if dsu.rank[xroot] < dsu.rank[yroot] {
		dsu.parent[xroot] = yroot
	} else {
		dsu.parent[yroot] = xroot
		if dsu.rank[xroot] == dsu.rank[yroot] {
			dsu.rank[xroot]++
		}
	}
	dsu.count--
}

func solve(n int64, edges [][]int64, k int64) int64 {
	nInt := int(n)
	edgesSorted := make([][]int64, len(edges))
	copy(edgesSorted, edges)
	sort.Slice(edgesSorted, func(i, j int) bool {
		return edgesSorted[i][2] < edgesSorted[j][2]
