		dsu := NewDSU(nInt)
		for _, e := range edgesSorted {
			if e[2] <= mid {
				dsu.union(int(e[0]), int(e[1]))
			}
		}
		if dsu.count <= int(k) {
			ans = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}
	return ans
}
