package main

import (
	"sort"
)

type DSU struct {
	parent []int
	rank   []int
	count  int
}

func NewDSU(n int) *DSU {
	parent := make([]int, n)
	rank := make([]int, n)
	for i := 0; i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}
	return &DSU{
		parent: parent,
		rank:   rank,
		count:  n,
	}
}

func (d *DSU) Find(x int) int {
	if d.parent[x] != x {
		d.parent[x] = d.Find(d.parent[x])
	}
	return d.parent[x]
}

func (d *DSU) Union(x, y int) {
	xroot := d.Find(x)
	yroot := d.Find(y)
	if xroot == yroot {
		return
	}
	if d.rank[xroot] < d.rank[yroot] {
		d.parent[xroot] = yroot
	} else {
		d.parent[yroot] = xroot
		if d.rank[xroot] == d.rank[yroot] {
			d.rank[xroot]++
		}
	}
	d.count--
}

func solve(n int64, edges [][]int64, k int64) int64 {
	nInt := int(n)
	sortedEdges := make([][]int64, len(edges))
	copy(sortedEdges, edges)
	sort.Slice(sortedEdges, func(i, j int) bool {
		return sortedEdges[i][2] < sortedEdges[j][2]
	})

	maxW := 0
	for _, e := range edges {
		if e[2] > int64(maxW) {
			maxW = int(e[2])
		}
	}

	low := 0
	high := int64(maxW)
	answer := int64(high)

	for low <= high {
		mid := (low + high) / 2
		dsu := NewDSU(nInt)
		for _, e := range sortedEdges {
			if e[2] <= mid {
				dsu.Union(int(e[0]), int(e[1]))
			}
		}
		if dsu.count <= k {
			answer = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}
	return answer
}
